import './CircleProgress.scss';

import type { FC } from 'react';
import React, { useMemo } from 'react';

import { classNames } from '../../../helpers/classnames';
import type { CircleProgressProps } from './CircleProgress.types';

//todo переделать, после смены токенов придётся и тут менять
const sizeDictionary = {
	standart: 44,
	mini: 20,
};

const strokeWidthDictionary = {
	standart: 6,
	mini: 3,
};

// для совместимости number
const getRadius = (size: number | string): number => {
	const key = size in sizeDictionary ? size : 'standart';
	return (sizeDictionary[key] - strokeWidthDictionary[key]) / 2;
};

export const CircleProgress: FC<CircleProgressProps> = ({
	value = 0,
	size = 'standart',
	cycled = false,
	className,
	...props
}) => {
	const radius = useMemo(() => getRadius(size), [size]);

	const CIRCUMFERENCE = useMemo(() => radius * 2 * Math.PI, [radius]);

	const strokeDasharray = `${CIRCUMFERENCE} ${CIRCUMFERENCE}`;

	const limitedValue = useMemo(() => Math.min(value, 100), [value]);

	const completed = useMemo(() => limitedValue === 100, [limitedValue]);

	const strokeDashoffset = useMemo(
		() => CIRCUMFERENCE - (limitedValue / 100) * CIRCUMFERENCE,
		[CIRCUMFERENCE, limitedValue],
	);

	return (
		<div
			data-testid="CircleProgress"
			{...props}
			className={classNames('dsb_progress__circular-wrapper', className)}
			role="progressbar"
			aria-valuenow={value}
			aria-valuemax={100}
			aria-valuemin={0}
		>
			<svg
				className={classNames(
					'dsb_progress',
					size === 'mini' ? 'dsb_progress__circular_mini' : 'dsb_progress__circular_standart',
				)}
			>
				<circle className="dsb_progress-circle__track" />
				<circle
					className={classNames(
						'dsb_progress-circle__indication',
						cycled && 'dsb_progress-circle__cycled',
						completed && 'dsb_progress-circle__indication_completed',
					)}
					style={{ strokeDashoffset, strokeDasharray }}
				/>
			</svg>
		</div>
	);
};
